#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long n,m; int k; scanf("%lld %lld", &n, &m);
        scanf("%d", &k);
        for(int i=0;i<k;i++){
            int x,y; scanf("%d %d", &x, &y);
        }
        printf("%s\n", (k%2==0)?"YES":"NO");
    }
    return 0;
}

